import{_ as o,o as i,c as l,ai as d}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"思考级别","description":"","frontmatter":{"read_when":["调整思考或详细模式指令解析或默认值时"],"summary":"`/think` + `/verbose` 的指令语法及其对模型推理的影响","title":"思考级别","x-i18n":{"generated_at":"2026-02-01T21:43:37Z","model":"claude-opus-4-5","provider":"pi","source_hash":"1a611474c2781c9a8e9dac0e084e7ee4ef58aebece181fdc877392fc27442746","source_path":"tools/thinking.md","workflow":15}},"headers":[],"relativePath":"zh-CN/tools/thinking.md","filePath":"zh-CN/tools/thinking.md","lastUpdated":null}'),t={name:"zh-CN/tools/thinking.md"};function c(a,e,n,h,r,s){return i(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="思考级别-think-指令" tabindex="-1"><a class="header-anchor" href="#思考级别-think-指令">#</a> 思考级别（/think 指令）</h1><h2 id="功能说明" tabindex="-1"><a class="header-anchor" href="#功能说明">#</a> 功能说明</h2><ul><li>在任何入站消息正文中使用内联指令：<code>/t &lt;level&gt;</code>、<code>/think:&lt;level&gt;</code> 或 <code>/thinking &lt;level&gt;</code>。</li><li>级别（别名）：<code>off | minimal | low | medium | high | xhigh</code>（仅 GPT-5.2 + Codex 模型） <ul><li>minimal → &quot;think&quot;</li><li>low → &quot;think hard&quot;</li><li>medium → &quot;think harder&quot;</li><li>high → &quot;ultrathink&quot;（最大预算）</li><li>xhigh → &quot;ultrathink+&quot;（仅 GPT-5.2 + Codex 模型）</li><li><code>highest</code>、<code>max</code> 映射为 <code>high</code>。</li></ul></li><li>提供商说明： <ul><li>Z.AI（<code>zai/*</code>）仅支持二元思考（<code>on</code>/<code>off</code>）。任何非 <code>off</code> 级别均视为 <code>on</code>（映射为 <code>low</code>）。</li></ul></li></ul><h2 id="解析优先顺序" tabindex="-1"><a class="header-anchor" href="#解析优先顺序">#</a> 解析优先顺序</h2><ol><li>消息上的内联指令（仅适用于该条消息）。</li><li>会话覆盖（通过发送仅包含指令的消息设置）。</li><li>全局默认值（配置中的 <code>agents.defaults.thinkingDefault</code>）。</li><li>回退：具备推理能力的模型为 low；否则为 off。</li></ol><h2 id="设置会话默认值" tabindex="-1"><a class="header-anchor" href="#设置会话默认值">#</a> 设置会话默认值</h2><ul><li>发送一条<strong>仅包含</strong>指令的消息（允许空白），例如 <code>/think:medium</code> 或 <code>/t high</code>。</li><li>该设置在当前会话中持续生效（默认按发送者）；通过 <code>/think:off</code> 或会话空闲重置来清除。</li><li>会发送确认回复（<code>Thinking level set to high.</code> / <code>Thinking disabled.</code>）。如果级别无效（例如 <code>/thinking big</code>），命令将被拒绝并给出提示，会话状态保持不变。</li><li>不带参数发送 <code>/think</code>（或 <code>/think:</code>）可查看当前思考级别。</li></ul><h2 id="按智能体应用" tabindex="-1"><a class="header-anchor" href="#按智能体应用">#</a> 按智能体应用</h2><ul><li><strong>内嵌 Pi</strong>：解析后的级别传递给进程内的 Pi 智能体运行时。</li></ul><h2 id="详细模式指令-verbose-或-v" tabindex="-1"><a class="header-anchor" href="#详细模式指令-verbose-或-v">#</a> 详细模式指令（/verbose 或 /v）</h2><ul><li>级别：<code>on</code>（最小）| <code>full</code> | <code>off</code>（默认）。</li><li>仅包含指令的消息切换会话详细模式并回复 <code>Verbose logging enabled.</code> / <code>Verbose logging disabled.</code>；无效级别返回提示且不改变状态。</li><li><code>/verbose off</code> 存储一个显式的会话覆盖；通过会话 UI 选择 <code>inherit</code> 来清除。</li><li>内联指令仅影响该条消息；否则应用会话/全局默认值。</li><li>不带参数发送 <code>/verbose</code>（或 <code>/verbose:</code>）可查看当前详细模式级别。</li><li>启用详细模式后，发出结构化工具结果的智能体（Pi 及其他 JSON 智能体）会将每个工具调用作为独立的元数据消息发回，可用时以 <code>&lt;emoji&gt; &lt;tool-name&gt;: &lt;arg&gt;</code> 为前缀（路径/命令）。这些工具摘要在每个工具启动时立即发送（独立气泡），而非作为流式增量。</li><li>当详细模式为 <code>full</code> 时，工具输出也会在完成后转发（独立气泡，截断至安全长度）。如果在运行过程中切换 <code>/verbose on|full|off</code>，后续的工具气泡会遵循新设置。</li></ul><h2 id="推理可见性-reasoning" tabindex="-1"><a class="header-anchor" href="#推理可见性-reasoning">#</a> 推理可见性（/reasoning）</h2><ul><li>级别：<code>on|off|stream</code>。</li><li>仅包含指令的消息切换回复中是否显示思考块。</li><li>启用时，推理内容作为<strong>独立消息</strong>发送，以 <code>Reasoning:</code> 为前缀。</li><li><code>stream</code>（仅 Telegram）：在回复生成期间将推理内容流式输出到 Telegram 草稿气泡中，然后发送不包含推理的最终回答。</li><li>别名：<code>/reason</code>。</li><li>不带参数发送 <code>/reasoning</code>（或 <code>/reasoning:</code>）可查看当前推理级别。</li></ul><h2 id="相关内容" tabindex="-1"><a class="header-anchor" href="#相关内容">#</a> 相关内容</h2><ul><li>提权模式文档位于<a href="/docs/tools/elevated">提权模式</a>。</li></ul><h2 id="心跳" tabindex="-1"><a class="header-anchor" href="#心跳">#</a> 心跳</h2><ul><li>心跳探测正文为配置的心跳提示词（默认：<code>Read HEARTBEAT.md if it exists (workspace context). Follow it strictly. Do not infer or repeat old tasks from prior chats. If nothing needs attention, reply HEARTBEAT_OK.</code>）。心跳消息中的内联指令照常生效（但避免从心跳中更改会话默认值）。</li><li>心跳投递默认仅包含最终负载。要同时发送单独的 <code>Reasoning:</code> 消息（如果可用），请设置 <code>agents.defaults.heartbeat.includeReasoning: true</code> 或按智能体 <code>agents.list[].heartbeat.includeReasoning: true</code>。</li></ul><h2 id="web-聊天-ui" tabindex="-1"><a class="header-anchor" href="#web-聊天-ui">#</a> Web 聊天 UI</h2><ul><li>Web 聊天的思考选择器在页面加载时从入站会话存储/配置中读取并反映会话的已存储级别。</li><li>选择另一个级别仅应用于下一条消息（<code>thinkingOnce</code>）；发送后，选择器会回到已存储的会话级别。</li><li>要更改会话默认值，请发送 <code>/think:&lt;level&gt;</code> 指令（和之前一样）；选择器将在下次刷新后反映该设置。</li></ul>',19)])])}const f=o(t,[["render",c]]);export{g as __pageData,f as default};
